light": {
      "description": "Big numbers that tell a story. 2-4 stats with context.",
      "rules": [
        "Stat boxes: value (48px bold colored) + label (18px secondary)",
        "Use grid-template-columns: 1fr 1fr — never flex for stat layout",
        "Each stat a different accent color for visual variety",
        "2 stats = 1 row, 3-4 stats = 2 rows. Never 3 columns (too cramped at 936px)",
        "Stat values should be short: numbers, percentages, or 1-2 word labels",
        "Context card explains what the numbers mean"
      ],
      "structure": [
        {
          "element": "slide-label"
        },
        {
          "element": "title",
          "font": "slideTitle (58px)",
          "heightBudget": 140,
          "maxLines": 2
        },
        {
          "element": "subtitle",
          "font": "subtitle (28px)",
          "heightBudget": 90,
          "maxLines": 2
        },
        {
          "element": "stat-grid",
          "heightBudget": 350,
          "layout": "grid, 2 columns",
          "maxItems": 4
        },
        {
          "element": "context-card",
          "heightBudget": 120,
          "optional": true
        },
